Para configurar a session persistence com CLI ou Terraform, você precisará criar um recurso Load Balancer e configurar o backend set e o listener. Aqui está um exemplo de como fazer isso com Terraform:

**Arquivo de configuração (main.tf)**
```terraform
# Configuração do provider AWS
provider "aws" {
  region = "sa-saopaulo-1"
}

# Criação da VM
resource "aws_instance" "vm" {
  ami           = "ami-0c94855ba95c71c99"
  instance_type = "t3.2.xlarge"
  key_name      = "my-key"
  vpc_security_group_ids = ["sg-0123456789abcdef0"]
  tags = {
    Name = "SecureBank Corp - VM"
  }
}

# Criação do subnet
resource "aws_subnet" "subnet" {
  cidr_block = "172.16.0.0/16"
  vpc_id     = aws_vpc.vpc.id
  availability_zone = "sa-saopaulo-1"
  map_public_ip_on_launch = true
  tags = {
    Name = "SecureBank Corp - Subnet"
  }
}

# Criação da VPC
resource "aws_vpc" "vpc" {
  cidr_block = "172.16.0.0/16"
  tags = {
    Name = "SecureBank Corp - VPC"
  }
}

# Criação do security group
resource "aws_security_group" "sg" {
  name        = "SecureBank Corp - Security Group"
  description = "Security group para a SecureBank Corp"
  vpc_id      = aws_vpc.vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "SecureBank Corp - Security Group"
  }
}

# Criação do load balancer
resource "aws_lb" "lb" {
  name               = "SecureBank Corp - Load Balancer"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.sg.id]
  subnets            = [aws_subnet.subnet.id]
}

# Criação do listener
resource "aws_lb_listener" "listener" {
  load_balancer_arn = aws_lb.lb.arn
  port              = "80"
  protocol          = "HTTP"
  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

# Criação do target group
resource "aws_lb_target_group" "tg" {
  name     = "SecureBank Corp - Target Group"
  port     = "80"
  protocol = "HTTP"
  vpc_id   = aws_vpc.vpc.id
}

# Criação do backend set
resource "aws_lb_target_group_attachment" "attachment" {
  target_group_arn = aws_lb_target_group.tg.arn
  index             = 0
  port              = 80
  resource_id       = aws_instance.vm.id
}

# Criação da session persistence
resource "aws_lb_policy" "policy" {
  name        = "SecureBank Corp - Session Persistence Policy"
  policy      = jsonencode({
    Version: "2012-10-17",
    Statement: [
      {
        Action: "execute-api:invoke",
        Resource: "${aws_lb.lb.arn}/*",
        Effect: "Allow",
        Sid: "AllowInvoke",
        Principal: {
          Service: "lambda.amazonaws.com"
        }
      }
    ]
  })
  depends_on = [aws_lb_listener.listener]
}

# Criação da session persistence policy
resource "aws_lb_policy_attachment" "attachment" {
  name        = "SecureBank Corp - Session Persistence Policy Attachment"
  policy_arn = aws_lb_policy.policy.arn
  target_id   = aws_lb.listener.arn
  target_type = "listener"
}
```
