**1. Criar um bucket do Azure Blob Storage**

```haskell
resource "azurerm_resource_group" "rg" {
  name     = "ca-toronto-1"
  location = "canada-central"
}

resource "azurerm_resource_group_variable" "storage_account_key" {
  name                 = "storage_account_key"
  resource_group_name = azurerm_resource_group.rg.name
  value               = var.storage_account_key
}

resource "azurerm_storage_account" "sa" {
  name                     = "ca-toronto-1-blobstorage"
  resource_group_name     = azurerm_resource_group.rg.name
  location                 = "canada-central"
  account_tier             = "Standard"
  account_replication_type = "LRS"

  dynamic "queue" {
    for_each = var.buckets
    content {
      name = queue.value
    }
  }
}
```

**2. Configurar a autenticação de pre-autenticação**

```haskell
resource "azurerm_storage_account_access_policy" "ap" {
  resource_group_name = azurerm_resource_group.rg.name
  storage_account_name = azurerm_storage_account.sa.name
  access_policy_name   = "access-policy"

  role "reader" {
    start_time = "2022-01-01T00:00:00Z"
    end_time   = "2038-01-19T03:14:07Z"
  }

  role "writer" {
    start_time = "2022-01-01T00:00:00Z"
    end_time   = "2038-01-19T03:14:07Z"
  }
}
```

**3. Criar uma política de vida**

```haskell
resource "azurerm_storage_blob_lifecycle_policy" "lp" {
  resource_group_name = azurerm_resource_group.rg.name
  storage_account_name = azurerm_storage_account.sa.name
  blob_name               = var.blobs

  rule {
    id = "rule-1"
    status = "DeleteAfterRead"

    days_to_delete = 30
  }
}
```

**4. Ativar a versão**

```haskell
resource "azurerm_storage_blob_versioning" "v" {
  resource_group_name = azurerm_resource_group.rg.name
  storage_account_name = azurerm_storage_account.sa.name
  blob_name               = var.blobs

  versioning_configuration {
    versioning_status = "Enabled"
  }
}
```

**5. Expor o bucket para o Terraform**

```haskell
output "storage_account_key" {
  value = azurerm_storage_account.sa.storage_account_key
}

output "storage_account_url" {
  value = azurerm_storage_account.sa.resource_id
}

output "storage_account_name" {
  value = azurerm_storage_account.sa.name
}

output "storage_account_id" {
  value = azurerm_storage_account.sa.id
}
```

**Observações**

* Certifique-se de substituir os valores `storage_account_key`, `var.buckets`, `var.blobs` e `var.buckets` com os valores corretos para o seu projeto.
* A política de vida é configurada para deletar os blobs após 30 dias de inatividade.
* A versão é ativada para todos os blobs no bucket.

